bool solve(vector<int>& nums) {
	int n = nums[0];
	int m = nums[1];
	if (n == 0 || m == 0)
		return 1;
	int dp[n][m];
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			if (i == 0 && j == 0)
				dp[i][j] = 1;
			else if (i == 0)
				dp[i][j] = dp[i][j-1];
			else if (j == 0)
				dp[i][j] = dp[i-1][j];
			else
				dp[i][j] = dp[i-1][j] + dp[i][j-1];
		}
	}
	return dp[n-1][m-1];
}

