class Solution {
public:
bool solve(vector<int>& nums) {
	int n = nums[0];
	int m = nums[1];
	if (n == 0 || m == 0)
		return true;
	int dp[n][m];
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			if (i == n-1 && j == m-1)
				dp[i][j] = 1;
			else if (i == n-1)
				dp[i][j] = dp[i][j-1];
			else if (j == m-1)
				dp[i][j] = dp[i-1][j];
			else
				dp[i][j] = dp[i-1][j] + dp[i][j-1];
		}
	}
	return dp[n-1][m-1] != 0;
}
};
int main() {
	cin >> n >> m;
	vector<int> nums(2);
	nums[0] = n;
	nums[1] = m;
	Solution solution;
	cout << (solution.solve(nums) ? "YES" : "NO") << endl;
	return 0;
}
